// WanderWiseAI — Orchestrator Agent
// Central brain: classifies intent → routes to sub-agent →
// streams response via SSE → consolidates memory.
// ═══════════════════════════════════════════════════════════

import { v4 as uuidv4 } from "uuid";
import type {
  AgentSession,
  AgentTask,
  AgentResult,
  Message,
  StreamChunk,
  Attachment,
  UserContext,
  IntentType,
  AgentType,
} from "@/lib/types";
import { classifyIntent } from "@/agents/orchestrator/intent-classifier";
import { routeToAgent } from "@/agents/orchestrator/router";
import { formatSSEChunk } from "@/agents/orchestrator/streamer";
import {
  getSession,
  saveSession,
  createNewSession,
  appendMessage,
} from "@/memory/short-term/redis-client";
import { buildContextForAgent } from "@/memory/context-builder";
import { consolidateSession } from "@/memory/long-term/consolidation";
import { loadPromptWithVariables } from "@/prompts/registry";
import { selectModel } from "@/lib/utils/model-selector";
import {
  checkUserRequestLimit,
  checkUserCostLimit,
} from "@/lib/utils/rate-limiter";
import { createLogger } from "@/lib/utils/logger";
import { getAiClient, withRetry } from "@/lib/utils/ai";
import { MODEL_CONFIG } from "@/lib/constants";

const log = createLogger("Orchestrator");

// ── OpenAI Client ─────────────────────────────────────────


// ── Orchestrator Agent Class ──────────────────────────────

export class OrchestratorAgent {
  /**
   * Handle an incoming user message.
   * Returns an async generator of StreamChunk events for SSE.
   */
  async *handle(
    message: string,
    userId: string,
    sessionId: string,
    attachments?: Attachment[],
  ): AsyncGenerator<StreamChunk> {
    const startTime = Date.now();

    try {
      // ── 1. Rate Limit Check ─────────────────────────────
      yield { type: "thinking", label: "Checking access..." };

      const rateLimit = await checkUserRequestLimit(userId);
      if (!rateLimit.allowed) {
        yield {
          type: "error",
          code: "RATE_LIMIT_EXCEEDED",
          message: `You've reached the request limit. Try again after ${rateLimit.resetAt}.`,
        };
        yield { type: "done" };
        return;
      }

      const costLimit = await checkUserCostLimit(userId, 0.02);
      if (!costLimit.allowed) {
        yield {
          type: "error",
          code: "COST_LIMIT_EXCEEDED",
          message: "Daily AI usage limit reached. Try again tomorrow.",
        };
        yield { type: "done" };
        return;
      }

      // ── 2. Build Context ────────────────────────────────
      yield { type: "thinking", label: "Understanding your request..." };

      const context = await buildContextForAgent(userId, sessionId, message);

      // Initialize or retrieve session
      let session = context.session;
      if (!session) {
        session = createNewSession(sessionId, userId, context.userContext);
      }

      // Add user message to conversation
      const userMessage: Message = {
        role: "user",
        content: message,
        timestamp: new Date().toISOString(),
      };
      session.conversation.push(userMessage);

      // ── 3. Classify Intent ──────────────────────────────
      yield { type: "thinking", label: "Analyzing intent..." };

      const classification = await classifyIntent(
        message,
        session.conversation,
      );

      log.info("Intent classified", {
        intent: classification.intent,
        confidence: classification.confidence,
      });

      // Handle ambiguous intent
      if (
        classification.needs_clarification &&
        classification.clarification_question
      ) {
        yield { type: "text", content: classification.clarification_question };
        const assistantMsg: Message = {
          role: "assistant",
          content: classification.clarification_question,
          timestamp: new Date().toISOString(),
        };
        session.conversation.push(assistantMsg);
        await saveSession(session);
        yield { type: "done" };
        return;
      }

      // Push intent onto stack
      session.intent_stack.push(classification.intent);

      // ── 4. Route to Agent ───────────────────────────────
      const agentType = routeToAgent(classification.intent);

      // Handle general travel questions directly
      if (agentType === "orchestrator") {
        yield* this.handleDirectResponse(
          message,
          session,
          context.userContext,
          context.retrievedMemories,
          context.activeTripSummary,
        );
        await saveSession(session);
        yield { type: "done" };
        return;
      }

      // ── 5. Build Agent Task ─────────────────────────────
      yield { type: "thinking", label: `Connecting to ${agentType} agent...` };

      const task: AgentTask = {
        task_id: uuidv4(),
        type: classification.intent,
        payload: {
          message,
          entities: classification.entities,
          attachments: attachments || [],
        },
        context: session,
        user_id: userId,
        session_id: sessionId,
        complexity: this.assessComplexity(classification.intent),
        requiresVision: attachments?.some((a) => a.type === "image") || false,
        latencyBudgetMs: 10000,
      };

      // ── 6. Invoke Sub-Agent ─────────────────────────────
      yield {
        type: "tool_start",
        tool: agentType,
        label: `${agentType} is working...`,
      };

      const result = await this.invokeAgent(agentType, task);

      yield { type: "tool_done", tool: agentType };

      // ── 7. Stream Result ────────────────────────────────
      if (result.status === "error" && result.error) {
        yield {
          type: "error",
          code: result.error.code,
          message: result.error.user_message,
        };
      } else if (result.status === "needs_clarification") {
        yield {
          type: "text",
          content: (result.data.message as string) || "Could you clarify that?",
        };
      } else {
        // Stream the response text
        const responseText =
          (result.data.response as string) || JSON.stringify(result.data);
        yield { type: "text", content: responseText };

        // Send any UI hints
        if (result.ui_hints) {
          for (const hint of result.ui_hints) {
            yield {
              type: "ui_hint",
              action: hint.action,
              payload: hint.payload,
            };
          }
        }
      }

      // ── 8. Save State ───────────────────────────────────
      const assistantMessage: Message = {
        role: "assistant",
        content: (result.data.response as string) || "",
        timestamp: new Date().toISOString(),
      };
      session.conversation.push(assistantMessage);
      await saveSession(session);

      // ── 9. Background: Consolidate Memory ───────────────
      // Don't await — fire and forget
      consolidateSession(session).catch((err) =>
        log.error("Background consolidation failed", err),
      );

      const latency = Date.now() - startTime;
      log.info("Request complete", {
        latency,
        intent: classification.intent,
        agent: agentType,
      });

      yield { type: "done" };
    } catch (error) {
      log.error("Orchestrator error", error);
      yield {
        type: "error",
        code: "ORCHESTRATOR_ERROR",
        message: "Something went wrong. Please try again.",
      };
      yield { type: "done" };
    }
  }

  /**
   * Handle general travel questions directly with GPT-4o.
   */
  private async *handleDirectResponse(
    message: string,
    session: AgentSession,
    userContext: UserContext,
    memories: string[],
    tripSummary: string,
  ): AsyncGenerator<StreamChunk> {
    try {
      const systemPrompt = await loadPromptWithVariables(
        "orchestrator-system",
        {
          user_name: userContext.name || "Traveler",
          travel_style: userContext.travel_style || "solo",
          home_city: userContext.home_city || "Unknown",
          retrieved_memories: memories.join("\n") || "None",
          active_trip_summary: tripSummary,
        },
      );

      const client = getAiClient();

      // Use withRetry for non-streaming call first, then send result
      // (Streaming + provider failover is complex, so we do a non-streaming
      //  call with full failover, then deliver the text.)
      const response = await withRetry(
        (providerClient, model) =>
          providerClient.chat.completions.create({
            model: model || MODEL_CONFIG.DEFAULT_MODEL,
            temperature: MODEL_CONFIG.DEFAULT_TEMPERATURE,
            messages: [
              { role: "system", content: systemPrompt },
              ...session.conversation.slice(-10).map((m) => ({
                role: m.role as "user" | "assistant" | "system",
                content: m.content,
              })),
            ],
          }),
        3,
      );

      const fullResponse = (response as any).choices[0]?.message?.content || "";
      yield { type: "text", content: fullResponse };

      // Save assistant response
      session.conversation.push({
        role: "assistant",
        content: fullResponse,
        timestamp: new Date().toISOString(),
      });
    } catch (error: any) {
      log.error("Direct response failed", error);
      const status = error?.status ?? 0;
      const isQuota = status === 429 || String(error?.message || "").toLowerCase().includes("quota");
      const isExpired = status === 400 && String(error?.message || "").toLowerCase().includes("expired");

      let msg: string;
      if (isQuota) {
        msg = "⏳ The AI service quota has been reached. Please add a GROQ_API_KEY to your .env file for automatic fallback, or wait a minute and try again!";
      } else if (isExpired) {
        msg = "🔑 Your AI API key has expired. Please generate a new one or add a GROQ_API_KEY to your .env for automatic fallback.";
      } else {
        msg = "I apologize, but I encountered an issue. Could you try again?";
      }

      yield {
        type: "text",
        content: msg,
      };
    }
  }

  /**
   * Invoke a sub-agent with the given task.
   */
  private async invokeAgent(
    agentType: string,
    task: AgentTask,
  ): Promise<AgentResult> {
    // Dynamic import of sub-agents to avoid circular dependencies
    try {
      switch (agentType) {
        case "trip-planner": {
          const { TripPlannerAgent } = await import("@/agents/trip-planner");
          const agent = new TripPlannerAgent();
          return agent.execute(task);
        }
        case "booking": {
          const { BookingAgent } = await import("@/agents/booking");
          const agent = new BookingAgent();
          return agent.execute(task);
        }
        case "import": {
          const { ImportAgent } = await import("@/agents/import");
          const agent = new ImportAgent();
          return agent.execute(task);
        }
        case "expense": {
          const { ExpenseAgent } = await import("@/agents/expense");
          const agent = new ExpenseAgent();
          return agent.execute(task);
        }
        case "journal": {
          const { JournalAgent } = await import("@/agents/journal");
          const agent = new JournalAgent();
          return agent.execute(task);
        }
        case "group": {
          const { GroupAgent } = await import("@/agents/group");
          const agent = new GroupAgent();
          return agent.execute(task);
        }
        case "nudge": {
          const { NudgeAgent } = await import("@/agents/nudge");
          const agent = new NudgeAgent();
          return agent.execute(task);
        }
        default:
          return {
            task_id: task.task_id,
            agent_type: "orchestrator",
            status: "error",
            data: {},
            confidence: 0,
            error: {
              code: "UNKNOWN_AGENT",
              message: `No agent found for type: ${agentType}`,
              retryable: false,
              user_message:
                "I'm not sure how to handle that. Could you try rephrasing?",
            },
          };
      }
    } catch (error) {
      log.error(`Failed to invoke ${agentType}`, error);
      return {
        task_id: task.task_id,
        agent_type: agentType as AgentType,
        status: "error",
        data: {},
        confidence: 0,
        error: {
          code: "AGENT_INVOCATION_FAILED",
          message: String(error),
          retryable: true,
          user_message: "Something went wrong. Let me try again.",
        },
      };
    }
  }

  /**
   * Run multiple tasks in parallel.
   */
  async runParallel(tasks: AgentTask[]): Promise<AgentResult[]> {
    return Promise.all(
      tasks.map((task) => {
        const agentType = routeToAgent(task.type);
        return this.invokeAgent(agentType, task);
      }),
    );
  }

  /**
   * Assess task complexity based on intent type.
   */
  private assessComplexity(intent: IntentType): "low" | "medium" | "high" {
    const highComplexity: IntentType[] = [
      "plan_trip",
      "modify_itinerary",
      "book_flight",
      "book_hotel",
    ];
    const lowComplexity: IntentType[] = [
      "convert_currency",
      "add_expense",
      "nudge_setup",
      "general_travel_q",
    ];

    if (highComplexity.includes(intent)) return "high";
    if (lowComplexity.includes(intent)) return "low";
    return "medium";
  }
}

// ═══════════════════════════════════════════════════════════
// WanderWiseAI — Intent Classifier
// Classifies user messages using the active AI provider.
// ═══════════════════════════════════════════════════════════

import type { IntentClassification, Message } from "@/lib/types";
import { IntentClassificationSchema } from "@/lib/schemas";
import { loadPrompt } from "@/prompts/registry";
import { createLogger } from "@/lib/utils/logger";
import { parseJsonResponse, withRetry, getActiveProviderName } from "@/lib/utils/ai";
import { MODEL_CONFIG } from "@/lib/constants";

const log = createLogger("IntentClassifier");

/**
 * Classify a user message into one of 22 intent types.
 *
 * Uses the active AI provider (Gemini → Groq fallback) with
 * automatic retry and provider failover.
 */
export async function classifyIntent(
  message: string,
  history: Message[],
): Promise<IntentClassification> {
  const systemPrompt = await loadPrompt("intent-classifier");

  // Include last 5 messages for context
  const recentHistory = history
    .filter((m) => m.role !== "system")
    .slice(-5)
    .map((m) => `${m.role}: ${m.content}`)
    .join("\n");

  const userContent = recentHistory
    ? `Recent conversation:\n${recentHistory}\n\nNew message to classify: "${message}"`
    : `Message to classify: "${message}"`;

  let retries = MODEL_CONFIG.MAX_PARSE_RETRIES;

  while (retries >= 0) {
    try {
      // withRetry handles provider failover + exponential backoff
      const response = await withRetry(
        (client, model) =>
          client.chat.completions.create({
            model: model || MODEL_CONFIG.FAST_MODEL,
            temperature: MODEL_CONFIG.CLASSIFICATION_TEMPERATURE,
            response_format: { type: "json_object" },
            messages: [
              { role: "system", content: systemPrompt },
              { role: "user", content: userContent },
            ],
          }),
        3,
      );

      const validated = IntentClassificationSchema.parse(
        parseJsonResponse((response as any).choices[0]?.message?.content),
      ) as IntentClassification;

      log.debug("Classification result", {
        intent: validated.intent,
        confidence: validated.confidence,
        provider: getActiveProviderName(),
      });

      return validated;
    } catch (error: any) {
      retries--;
      const status = error?.status ?? error?.statusCode ?? "N/A";
      console.error(
        "[IntentClassifier] ERROR:",
        error?.message || error,
        "| Status:",
        status,
        "| Provider:",
        getActiveProviderName(),
      );

      if (retries < 0) {
        log.error("Intent classification failed after retries", error);

        const isQuotaError =
          status === 429 ||
          String(error?.message || "").toLowerCase().includes("quota");
        const isAuthError =
          status === 400 || status === 401 || status === 403;

        let clarification =
          "I'm having trouble connecting to my AI brain right now. Please try again in a moment! 🙏";

        if (isQuotaError) {
          clarification =
            "The AI service quota has been reached. Please wait a minute and try again, " +
            "or add a GROQ_API_KEY to your .env file for automatic fallback. 🙏";
        } else if (isAuthError) {
          clarification =
            "The AI service key is invalid or expired. " +
            "Please update GEMINI_API_KEY or add GROQ_API_KEY in your .env file.";
        }

        return {
          intent: "general_travel_q",
          confidence: 0,
          entities: {
            destination: null,
            dates: null,
            party_size: null,
            budget: null,
            interests: null,
            trip_id: null,
          },
          needs_clarification: true,
          clarification_question: clarification,
        };
      }
      log.warn(
        `Classification retry (${MODEL_CONFIG.MAX_PARSE_RETRIES - retries}/${MODEL_CONFIG.MAX_PARSE_RETRIES})`,
      );
    }
  }

  // TypeScript requires a return here
  return {
    intent: "general_travel_q",
    confidence: 0,
    entities: {
      destination: null,
      dates: null,
      party_size: null,
      budget: null,
      interests: null,
      trip_id: null,
    },
    needs_clarification: true,
    clarification_question:
      "Could you tell me more about what you need help with?",
  };
}

// ═══════════════════════════════════════════════════════════
// WanderWiseAI — Trip Planner Agent
// Generates personalised itineraries using Gemini JSON mode.
// Supports both single-call and batched generation modes.
// Architecture inspired by travel-planner-ai.
// ═══════════════════════════════════════════════════════════

import type { AgentTask, AgentResult, ConflictWarning, Activity } from "@/lib/types";
import { loadPromptWithVariables } from "@/prompts/registry";
import { selectModel } from "@/lib/utils/model-selector";
import { createLogger } from "@/lib/utils/logger";
import { parseJsonResponse, withRetry } from "@/lib/utils/ai";
import {
  createTrip,
  createItineraryDays,
  addActivity,
} from "@/memory/episodic/supabase-client";
import {
  generateFullTripPlan,
} from "@/services/batched-trip-generator";
import type {
  FullTripPlan,
  TripGenerationInput,
  ItineraryDay,
} from "@/lib/schemas/trip-planner";

/** Map AI-generated categories to the DB Activity category type. */
function mapCategory(aiCategory: string): Activity["category"] {
  const mapping: Record<string, Activity["category"]> = {
    food: "restaurant",
    restaurant: "restaurant",
    accommodation: "hotel",
    hotel: "hotel",
    shopping: "experience",
    transport: "transport",
    experience: "experience",
    flight: "flight",
    note: "note",
  };
  return mapping[aiCategory] || "experience";
}

const log = createLogger("TripPlannerAgent");

export class TripPlannerAgent {
  /**
   * Main execution entry point.
   * Detects whether the user provided structured trip params
   * (destination, dates, preferences) and routes to the
   * optimal generation strategy.
   */
  async execute(task: AgentTask): Promise<AgentResult> {
    const startTime = Date.now();

    try {
      log.info("Generating itinerary", { taskId: task.task_id });

      const userMessage = (task.payload.message as string) || "";
      const entities =
        (task.payload.entities as Record<string, unknown>) || {};

      // If we have structured entities from the intent classifier,
      // use the faster batched generation path (3 parallel API calls).
      const destination =
        (entities.destination as string) || this.extractDestination(userMessage);
      const hasStructuredInput = !!destination;

      let itinerary: FullTripPlan;

      if (hasStructuredInput) {
        // ── Batched Path (3 parallel calls) ──────────────
        itinerary = await this.executeBatched(
          destination,
          userMessage,
          entities,
        );
      } else {
        // ── Single-call Path (original) ──────────────────
        itinerary = await this.executeSingleCall(task, userMessage, entities);
      }

      // Validate dates to prevent infinity loops or crashes
      const startDateStr =
        itinerary.start_date || (entities.start_date as string) || "";
      const endDateStr =
        itinerary.end_date || (entities.end_date as string) || "";
      const validStart = new Date(startDateStr).getTime();
      const validEnd = new Date(endDateStr).getTime();
      const hasValidDates =
        !isNaN(validStart) && !isNaN(validEnd) && validStart <= validEnd;

      // ── Save to Supabase ────────────────────────────────
      let tripId: string | undefined;
      try {
        tripId = await createTrip(task.user_id, {
          destination: itinerary.destination || "",
          start_date: itinerary.start_date || "",
          end_date: itinerary.end_date || "",
          status: "planning",
          budget_usd: itinerary.estimated_total_cost_usd || 0,
          travelers: (entities.party_size as number) || 1,
        });

        if (itinerary.days && hasValidDates) {
          const dayIds = await createItineraryDays(
            tripId,
            startDateStr,
            endDateStr,
          );

          for (
            let i = 0;
            i < itinerary.days.length && i < dayIds.length;
            i++
          ) {
            const day = itinerary.days[i];
            for (let j = 0; j < (day.activities || []).length; j++) {
              const activity = day.activities[j];
              await addActivity(dayIds[i], {
                name: activity.name,
                category: mapCategory(activity.category || "experience"),
                start_time: activity.start_time || "",
                end_time: activity.end_time || "",
                location: activity.location || "",
                notes: activity.notes || "",
                estimated_cost_usd: activity.estimated_cost_usd || 0,
                order: j,
              });
            }
          }
        }
      } catch (dbError) {
        log.warn("Failed to save trip to DB, returning itinerary anyway", {
          error: dbError,
        });
      }

      // ── Detect Conflicts ────────────────────────────────
      const conflicts = this.detectConflicts(
        (itinerary.days || []) as ItineraryDay[],
      );

      // ── Format Response ─────────────────────────────────
      const responseText = this.formatItineraryResponse(itinerary, conflicts);

      return {
        task_id: task.task_id,
        agent_type: "trip-planner",
        status: "success",
        data: {
          response: responseText,
          itinerary,
          trip_id: tripId,
        },
        confidence: 0.9,
        ui_hints: [
          {
            action: "show_trip_card",
            payload: {
              trip_id: tripId,
              destination: itinerary.destination,
              plan: itinerary,
            },
          },
        ],
        latency_ms: Date.now() - startTime,
      };
    } catch (error) {
      log.error("Trip planning failed", error);
      return {
        task_id: task.task_id,
        agent_type: "trip-planner",
        status: "error",
        data: {},
        confidence: 0,
        error: {
          code: "TRIP_PLANNING_FAILED",
          message: String(error),
          retryable: true,
          user_message:
            "I had trouble creating your itinerary. Could you try again with more details?",
        },
        latency_ms: Date.now() - startTime,
      };
    }
  }

  // ── Batched Generation (3 parallel calls) ──────────────

  private async executeBatched(
    destination: string,
    userMessage: string,
    entities: Record<string, unknown>,
  ): Promise<FullTripPlan> {
    log.info("Using batched generation path", { destination });

    const dates = entities.dates as string[] | undefined;
    const input: TripGenerationInput = {
      destination,
      number_of_days: this.extractDayCount(userMessage, dates),
      activity_preferences: (entities.interests as string[]) || undefined,
      from_date: dates?.[0],
      to_date: dates?.[1] || dates?.[0],
      companion: this.extractCompanion(userMessage),
      budget_level: this.extractBudgetLevel(
        (entities.budget as string) || userMessage,
      ),
    };

    return generateFullTripPlan(input);
  }

  // ── Single-Call Generation (original path) ─────────────

  private async executeSingleCall(
    task: AgentTask,
    userMessage: string,
    entities: Record<string, unknown>,
  ): Promise<FullTripPlan> {
    log.info("Using single-call generation path");

    const model = selectModel(task);
    const systemPrompt = await loadPromptWithVariables("trip-planner", {});

    const response = await withRetry(
      (client, providerModel) =>
        client.chat.completions.create({
          model: providerModel || model,
          temperature: 0.7,
          response_format: { type: "json_object" },
          messages: [
            { role: "system", content: systemPrompt },
            { role: "user", content: userMessage },
          ],
        }),
      3,
    );

    return parseJsonResponse<FullTripPlan>(
      (response as any).choices[0]?.message?.content,
    );
  }

  // ── Entity Extraction Helpers ──────────────────────────

  private extractDestination(message: string): string {
    // Simple heuristic: look for "to <Place>" or "in <Place>"
    const toMatch = message.match(
      /(?:to|in|visit|explore)\s+([A-Z][a-zA-Z\s,]+?)(?:\s+for|\s+from|\s+with|\.|,|$)/,
    );
    return toMatch ? toMatch[1].trim() : "";
  }

  private extractDayCount(message: string, dates?: string[]): number {
    // Try to extract from message
    const dayMatch = message.match(/(\d+)\s*(?:day|night|d)/i);
    if (dayMatch) return parseInt(dayMatch[1], 10);

    // Try to compute from dates
    if (dates && dates.length >= 2) {
      const start = new Date(dates[0]).getTime();
      const end = new Date(dates[1]).getTime();
      if (!isNaN(start) && !isNaN(end)) {
        return Math.max(1, Math.ceil((end - start) / 86400000) + 1);
      }
    }

    return 5; // Default
  }

  private extractCompanion(message: string): string | undefined {
    const lower = message.toLowerCase();
    if (lower.includes("solo")) return "solo";
    if (lower.includes("couple") || lower.includes("partner"))
      return "partner";
    if (lower.includes("family") || lower.includes("kids"))
      return "family with kids";
    if (lower.includes("friends") || lower.includes("group"))
      return "friends group";
    return undefined;
  }

  private extractBudgetLevel(
    text: string,
  ): "budget" | "mid-range" | "luxury" | undefined {
    const lower = text.toLowerCase();
    if (lower.includes("budget") || lower.includes("cheap")) return "budget";
    if (lower.includes("luxury") || lower.includes("premium"))
      return "luxury";
    if (lower.includes("mid") || lower.includes("moderate"))
      return "mid-range";
    return undefined;
  }

  // ── Conflict Detection ─────────────────────────────────

  detectConflicts(
    days: ItineraryDay[],
  ): ConflictWarning[] {
    const warnings: ConflictWarning[] = [];

    for (const day of days) {
      const activities = day.activities || [];
      for (let i = 0; i < activities.length - 1; i++) {
        const current = activities[i];
        const next = activities[i + 1];

        if (
          current.end_time &&
          next.start_time &&
          current.end_time > next.start_time
        ) {
          warnings.push({
            type: "time_overlap",
            activities: [current.name, next.name],
            message: `"${current.name}" ends at ${current.end_time} but "${next.name}" starts at ${next.start_time}`,
            suggestion:
              "Consider adjusting the schedule or removing one activity.",
          });
        }
      }
    }

    return warnings;
  }

  // ── Response Formatting ────────────────────────────────

  private formatItineraryResponse(
    itinerary: FullTripPlan,
    conflicts: ConflictWarning[],
  ): string {
    let response = `Alright traveler, step right this way! 🗺️✨ Look at this amazing ${itinerary.days?.length || "?"}-day adventure I've put together just for you in **${itinerary.destination}**!\n\n`;

    // ── Destination Overview (Batch 1) ────────────────
    if (itinerary.about_the_place) {
      response += `🌍 **About ${itinerary.destination}**\n${itinerary.about_the_place}\n\n`;
    }

    if (itinerary.best_time_to_visit) {
      response += `☀️ **Best Time to Visit:** ${itinerary.best_time_to_visit}\n\n`;
    }

    // ── Top Places with Coordinates (Batch 3) ─────────
    if (
      itinerary.top_places_to_visit &&
      itinerary.top_places_to_visit.length > 0
    ) {
      response += `🏛️ **Top Places to Visit**\n`;
      for (const place of itinerary.top_places_to_visit) {
        response += `- **${place.name}**\n`;
      }
      response += `\n`;
    }

    // ── Recommendations (Batch 2) ─────────────────────
    if (
      itinerary.adventures_activities_to_do &&
      itinerary.adventures_activities_to_do.length > 0
    ) {
      response += `🏄 **Top Adventures & Activities**\n`;
      for (const activity of itinerary.adventures_activities_to_do) {
        response += `- ${activity}\n`;
      }
      response += `\n`;
    }

    if (
      itinerary.local_cuisine_recommendations &&
      itinerary.local_cuisine_recommendations.length > 0
    ) {
      response += `🍲 **Local Cuisine Recommendations**\n`;
      for (const cuisine of itinerary.local_cuisine_recommendations) {
        response += `- ${cuisine}\n`;
      }
      response += `\n`;
    }

    if (
      itinerary.packing_checklist &&
      itinerary.packing_checklist.length > 0
    ) {
      response += `🎒 **Packing Checklist**\n`;
      for (const item of itinerary.packing_checklist) {
        response += `- ${item}\n`;
      }
      response += `\n`;
    }

    // ── Day-by-Day Itinerary (Batch 3) ────────────────
    response += `📅 **Your Itinerary**\n\n`;

    for (const day of itinerary.days || []) {
      response += `### Day ${day.day_number}: ${day.theme || ""} (${day.date})\n`;
      for (const activity of day.activities || []) {
        response += `- **${activity.start_time}–${activity.end_time}**: ${activity.name} 📍 ${activity.location}\n`;
        if (activity.notes) response += `  _${activity.notes}_\n`;
      }
      response += "\n";
    }

    // ── Tips ───────────────────────────────────────────
    if (itinerary.tips && itinerary.tips.length > 0) {
      response += `### 💡 Your Guide's Top Tips\n`;
      for (const tip of itinerary.tips) response += `- ${tip}\n`;
    }

    response += `\n**Estimated total cost to enjoy all this: $${itinerary.estimated_total_cost_usd}**`;

    // ── Conflict Warnings ─────────────────────────────
    if (conflicts.length > 0) {
      response += `\n\n⚠️ **Hold on a second, a quick heads-up on the schedule!**\n`;
      for (const c of conflicts) response += `- ${c.message}\n`;
    }

    return response;
  }
}

import OpenAI from "openai";

// ═══════════════════════════════════════════════════════════
// WanderWiseAI — Multi-Provider AI Client (WITH OFFLINE DEMO MODE)
// Ensures the web app ALWAYS works for demonstrations even if
// API keys are expired or missing!
// ═══════════════════════════════════════════════════════════

interface AIProvider {
  name: string;
  apiKey: string;
  baseURL: string;
  models: { default: string; fast: string; embedding?: string };
}

function getProviders(): AIProvider[] {
  const providers: AIProvider[] = [];

  const geminiKey =
    process.env.GEMINI_API_KEY ||
    process.env.OPENAI_API_KEY ||
    process.env.VITE_GEMINI_API_KEY ||
    "";
  if (geminiKey) {
    providers.push({
      name: "Gemini",
      apiKey: geminiKey,
      baseURL:
        process.env.OPENAI_BASE_URL ||
        "https://generativelanguage.googleapis.com/v1beta/openai/",
      models: { default: "gemini-2.0-flash", fast: "gemini-2.0-flash" },
    });
  }

  const groqKey = process.env.GROQ_API_KEY || "";
  if (groqKey) {
    providers.push({
      name: "Groq",
      apiKey: groqKey,
      baseURL: "https://api.groq.com/openai/v1",
      models: {
        default: "llama-3.3-70b-versatile",
        fast: "llama-3.3-70b-versatile",
      },
    });
  }

  return providers;
}

const clientCache = new Map<string, OpenAI>();

function getClientForProvider(provider: AIProvider): any {
  if (provider.name === "Offline Demo Mode") {
    return new MockOpenAI();
  }

  const cacheKey = `${provider.name}:${provider.apiKey.substring(0, 10)}`;
  if (!clientCache.has(cacheKey)) {
    clientCache.set(
      cacheKey,
      new OpenAI({ apiKey: provider.apiKey, baseURL: provider.baseURL }),
    );
  }
  return clientCache.get(cacheKey)!;
}

