  const allTags = [
    "Culture",
    "Adventure",
    "Food",
    "Nature",
    "History",
    "Nightlife",
    "Shopping",
    "Relaxation",
  ];

  const toggleTag = (tag: string) => {
    setTags((prev) =>
      prev.includes(tag) ? prev.filter((t) => t !== tag) : [...prev, tag],
    );
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  const location = useLocation();
  const hasAutoQueried = useRef(false);

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  useEffect(() => {
    if (location.state?.autoQuery && !hasAutoQueried.current) {
      hasAutoQueried.current = true;
      sendMessage(location.state.autoQuery);
    }
  }, [location.state]);

  const sendPromptToBackend = async (prompt: string) => {
    try {
      if (offlineMode) {
        // Direct call to local Ollama instance (Offline Mode) via Vite Proxy
        const res = await fetch("/ollama/api/generate", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ 
            model: "tinyllama", // Fallback to an ultra-lightweight model to prevent memory crashes
            prompt: prompt,
            stream: false 
          }),
        });

        const data = await res.json();
        if (!res.ok) {
           throw new Error(data.error || "Ollama API failed");
        }
        return data.response || "No response received from offline model.";
      }

      // Online API fallback
      const res = await fetch("/api/agent", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: prompt }),
      });
      if (!res.ok) throw new Error("API failed");

      const text = await res.text();
      const parsedMatches = text.match(/"content":"(.*?)"/g);
