  });

  try {
    const parsed = parseJsonResponse<any>(response.choices[0]?.message?.content);
    return (parsed.flights || []) as FlightOffer[];
  } catch {
    log.warn("Failed to parse GPT flight data");
    return [];
  }
}

export async function amadeusFlightSearch(
  input: z.infer<typeof amadeusFlightSearchSchema>,
): Promise<{ flights: FlightOffer[]; count: number; simulated?: boolean }> {
  // ── Fallback: use GPT when no Amadeus credentials ──────
  if (!hasAmadeusCredentials()) {
    log.info("Amadeus not configured, using AI-generated flight data", {
      origin: input.origin,
      destination: input.destination,
    });
    const flights = await generateSmartFlightResults(input);
    return {
      flights: flights.slice(0, 3),
      count: flights.length,
      simulated: true,
    };
  }

  // ── Real Amadeus API ───────────────────────────────────
  return amadeusBreaker.execute(async () => {
    try {
      log.info("Searching flights", {
        origin: input.origin,
        destination: input.destination,
      });

      const clientId = process.env.AMADEUS_CLIENT_ID || "";
      const clientSecret = process.env.AMADEUS_CLIENT_SECRET || "";

      // Auth
      const tokenRes = await fetch(
        "https://api.amadeus.com/v1/security/oauth2/token",
        {
          method: "POST",
          headers: { "Content-Type": "application/x-www-form-urlencoded" },
          body: `grant_type=client_credentials&client_id=${clientId}&client_secret=${clientSecret}`,
        },
      );
      const { access_token } = await tokenRes.json();

      // Search
      const params = new URLSearchParams({
        originLocationCode: input.origin,
        destinationLocationCode: input.destination,
        departureDate: input.date,
        adults: String(input.adults),
        max: "10",
      });
      if (input.returnDate) params.set("returnDate", input.returnDate);
      if (input.travelClass) params.set("travelClass", input.travelClass);

      const res = await fetch(
        `https://api.amadeus.com/v2/shopping/flight-offers?${params}`,
        {
          headers: { Authorization: `Bearer ${access_token}` },
        },
      );
      const data = await res.json();

      const flights: FlightOffer[] = (data.data || []).map(
        (offer: Record<string, unknown>) => {
          const itinerary = (
            offer.itineraries as Record<string, unknown>[]
          )?.[0];
          const segments =
            (itinerary?.segments as Record<string, unknown>[]) || [];
          const price = offer.price as Record<string, unknown>;

          return {
            offer_id: offer.id as string,
            airline: (segments[0]?.carrierCode as string) || "",
            airline_code: (segments[0]?.carrierCode as string) || "",
            departure:
              ((segments[0]?.departure as Record<string, unknown>)
                ?.at as string) || "",
            arrival:
              ((
                segments[segments.length - 1]?.arrival as Record<
                  string,
                  unknown
                >
              )?.at as string) || "",
            duration: (itinerary?.duration as string) || "",
            stops: segments.length - 1,
            price: parseFloat((price?.grandTotal as string) || "0"),
            currency: (price?.currency as string) || "USD",
            cabin_class: input.travelClass || "ECONOMY",
            segments: segments.map((seg: Record<string, unknown>) => ({
              departure_airport:
                ((seg.departure as Record<string, unknown>)
                  ?.iataCode as string) || "",
              arrival_airport:
                ((seg.arrival as Record<string, unknown>)
                  ?.iataCode as string) || "",
              departure_time:
                ((seg.departure as Record<string, unknown>)?.at as string) ||
                "",
              arrival_time:
                ((seg.arrival as Record<string, unknown>)?.at as string) || "",
              carrier: (seg.carrierCode as string) || "",
              flight_number: `${seg.carrierCode}${seg.number}`,
              duration: (seg.duration as string) || "",
            })),
          };
        },
      );

      // Sort: price → stops → duration
      flights.sort((a, b) => a.price - b.price || a.stops - b.stops);

      return { flights: flights.slice(0, 3), count: flights.length };
    } catch (error) {
      log.error("Flight search failed", error);
      throw error;
    }
  });
}

export const amadeusFlightSearchTool = {
  name: "amadeus_flight_search",
  description: "Search for flights between two airports on specific dates",
  schema: amadeusFlightSearchSchema,
  func: amadeusFlightSearch,
};

// ═══════════════════════════════════════════════════════════
// Tool: check_flight_status
// Checks real-time flight status via Amadeus Flight Status API.
// Falls back to GPT-generated status when Amadeus is unavailable.
// ═══════════════════════════════════════════════════════════

import { z } from "zod";
import { createLogger } from "@/lib/utils/logger";
import { getAiClient, parseJsonResponse } from "@/lib/utils/ai";
import { amadeusBreaker } from "@/lib/utils/circuit-breaker";
import type { FlightStatus } from "@/lib/types";

const log = createLogger("Tool:FlightStatus");



export const checkFlightStatusSchema = z.object({
  carrierCode: z.string().describe('Airline IATA code (e.g., "BA")'),
  flightNumber: z.string().describe('Flight number (e.g., "1234")'),
  date: z.string().describe("Flight date (YYYY-MM-DD)"),
});

/**
 * Check if Amadeus credentials are configured.
 */
function hasAmadeusCredentials(): boolean {
  return !!(process.env.AMADEUS_CLIENT_ID && process.env.AMADEUS_CLIENT_SECRET);
}

export async function checkFlightStatus(
  input: z.infer<typeof checkFlightStatusSchema>,
): Promise<{
  status: FlightStatus;
  delay_minutes?: number;
  departure?: string;
  arrival?: string;
  simulated?: boolean;
}> {
  // ── Fallback: use GPT for realistic status ─────────────
  if (!hasAmadeusCredentials()) {
    log.info("Amadeus not configured, generating simulated flight status", {
      flight: `${input.carrierCode}${input.flightNumber}`,
    });

    try {
      const client = getAiClient();
      const response = await client.chat.completions.create({
        model: "gpt-4o-mini",
        temperature: 0.3,
        response_format: { type: "json_object" },
        messages: [
          {
            role: "system",
            content: `You simulate flight status data. Given a flight, return a realistic status.
Most flights are on time (~85%). Some have minor delays (~10%). Rarely cancelled (~5%).
Respond with JSON: { "status": "on_time"|"delayed"|"cancelled", "delay_minutes": number|null }`,
          },
          {
            role: "user",
            content: `Flight ${input.carrierCode}${input.flightNumber} on ${input.date}`,
          },
        ],
      });

      const parsed = parseJsonResponse<any>(response.choices[0]?.message?.content);
      return {
        status: (parsed.status as FlightStatus) || "on_time",
        delay_minutes: parsed.delay_minutes || undefined,
        simulated: true,
      };
    } catch {
      log.warn("GPT flight status failed, returning on_time");
    }

    return { status: "on_time", simulated: true };
  }

  // ── Real Amadeus Flight Schedule API ───────────────────
  return amadeusBreaker.execute(async () => {
    try {
      log.info("Checking flight status", {
        flight: `${input.carrierCode}${input.flightNumber}`,
      });

      const clientId = process.env.AMADEUS_CLIENT_ID || "";
      const clientSecret = process.env.AMADEUS_CLIENT_SECRET || "";

      const tokenRes = await fetch(
        "https://api.amadeus.com/v1/security/oauth2/token",
        {
          method: "POST",
          headers: { "Content-Type": "application/x-www-form-urlencoded" },
          body: `grant_type=client_credentials&client_id=${clientId}&client_secret=${clientSecret}`,
        },
      );
      const { access_token } = await tokenRes.json();

      const params = new URLSearchParams({
        carrierCode: input.carrierCode,
        flightNumber: input.flightNumber,
        scheduledDepartureDate: input.date,
      });

      const res = await fetch(
        `https://api.amadeus.com/v2/schedule/flights?${params}`,
        { headers: { Authorization: `Bearer ${access_token}` } },
      );

      const data = await res.json();
      const flight = (data.data || [])[0];

      if (!flight) {
        return { status: "unknown" as FlightStatus };
      }

      const legs = flight.flightPoints || [];
      const departure = legs[0];
      const arrival = legs[legs.length - 1];

      // Determine delay
      const scheduledDep = departure?.departure?.timings?.find(
        (t: Record<string, unknown>) => t.qualifier === "STD",
      )?.value;
      const estimatedDep = departure?.departure?.timings?.find(
        (t: Record<string, unknown>) => t.qualifier === "ETD",
      )?.value;

      let delayMinutes: number | undefined;
      let status: FlightStatus = "on_time";

      if (scheduledDep && estimatedDep) {
        const scheduled = new Date(scheduledDep).getTime();
        const estimated = new Date(estimatedDep).getTime();
        delayMinutes = Math.round((estimated - scheduled) / 60000);

        if (delayMinutes > 15) {
          status = "delayed";
        }
      }

      return {
        status,
        delay_minutes: delayMinutes,
        departure: scheduledDep,
        arrival: arrival?.arrival?.timings?.find(
          (t: Record<string, unknown>) => t.qualifier === "STA",
        )?.value,
      };
    } catch (error) {
      log.error("Flight status check failed", error);
      return { status: "unknown" as FlightStatus };
    }
  });
}

export const checkFlightStatusTool = {
  name: "check_flight_status",
  description: "Check the current status of a flight",
  schema: checkFlightStatusSchema,
  func: checkFlightStatus,
};

